{
  "type": "Microsoft.Solutions/applications",
  "apiVersion": "2021-07-01",
  "name": "my-contoso-app",
  "location": "[resourceGroup().location]",
  "kind": "MarketPlace",
  "plan": {
    "name": "standard-v2",
    "product": "contoso-web-platform",
    "publisher": "contoso",
    "version": "2.0.0"
  },
  "properties": {
    "managedResourceGroupId": "[subscriptionResourceId('Microsoft.Resources/resourceGroups', 'my-contoso-app-mrg')]",
    "parameters": {
      "appName": { "value": "[parameters('appName')]" }
    }
  }
}

// ARM webhook notification payload (POST to ISV endpoint)
{
  "eventType": "PUT",
  "applicationId": "/subscriptions/<custSubId>/resourceGroups/consumer-rg/providers/Microsoft.Solutions/applications/my-contoso-app",
  "eventTime": "2024-03-01T12:00:00Z",
  "provisioningState": "Succeeded",
  "plan": {
    "name": "standard-v2",
    "product": "contoso-web-platform",
    "publisher": "contoso",
    "version": "2.0.0"
  },
  "applicationDefinitionId": null,
  "billingDetails": {
    "resourceUsageId": "<usage-tracking-guid>"
  },
  "authorizations": [
    {
      "principalId": "<isv-sp-object-id>",
      "roleDefinitionId": "b24988ac-6180-42a0-ab88-20f7382dd24c"
    }
  ]
}

// In mainTemplate.json — restricting what the customer can see
// The managedResourceGroupId lock is set by the offer's lockLevel
// To hide specific resources, use Azure deny assignments in the template:
{
  "type": "Microsoft.Authorization/denyAssignments",
  "apiVersion": "2022-04-01",
  "name": "[guid(resourceGroup().id, 'hide-keys')]",
  "properties": {
    "denyAssignmentName": "Deny direct key access",
    "permissions": [
      {
        "actions": [
          "Microsoft.KeyVault/vaults/secrets/read",
          "Microsoft.KeyVault/vaults/keys/read"
        ]
      }
    ],
    "principals": [
      {
        "id": "00000000-0000-0000-0000-000000000000",
        "type": "Everyone"
      }
    ],
    "excludePrincipals": [
      {
        "id": "<isv-sp-object-id>",
        "type": "ServicePrincipal"
      }
    ],
    "isSystemProtected": true
  }
}

{
  "type": "Microsoft.Solutions/applications",
  "apiVersion": "2021-07-01",
  "name": "my-private-offer-app",
  "location": "[resourceGroup().location]",
  "kind": "MarketPlace",
  "plan": {
    "name": "enterprise-v1",
    "product": "contoso-web-platform",
    "publisher": "contoso",
    "version": "1.5.0",
    "promotionCode": "ENTERPRISE-DISCOUNT-2024"
  },
  "properties": {
    "managedResourceGroupId": "[subscriptionResourceId('Microsoft.Resources/resourceGroups', 'private-offer-mrg')]",
    "parameters": {
      "appName": { "value": "[parameters('appName')]" }
    }
  }
}
